            <th style="padding: 12px; text-align: left; border-bottom: 1px solid #dee2e6; font-weight: 600; color: #495057;">Variable Name</th>
            <th style="padding: 12px; text-align: left; border-bottom: 1px solid #dee2e6; font-weight: 600; color: #495057;">Current Value</th>
            <th style="padding: 12px; text-align: left; border-bottom: 1px solid #dee2e6; font-weight: 600; color: #495057;">Type</th>
        </tr>
    \`;
    table.appendChild(thead);

    // Function to detect actual variable type
    function getVariableType(key, value) {
        const valueStr = String(value);

        // Check if it's an API variable placeholder (format: type_value_name)
        // This matches patterns like "string_value_string", "number_value_int", "boolean_value_bool"
        if (valueStr.includes('_value_')) {
            const match = valueStr.match(/^(string|number|boolean|integer)_value_/);
            if (match) {
                const detectedType = match[1];
                return detectedType === 'integer' ? 'number' : detectedType;
            }
        }

        // For actual boolean values
        if (value === true || value === false) {
            return 'boolean';
        }

        // For string representations of booleans
        if (valueStr === 'true' || valueStr === 'false') {
            return 'boolean';
        }

        // For actual numbers
        if (typeof value === 'number' && !isNaN(value)) {
            return Number.isInteger(value) ? 'integer' : 'number';
        }

        // For string representations of numbers
        if (!isNaN(Number(valueStr)) && valueStr.trim() !== '' && isFinite(Number(valueStr))) {
            const num = Number(valueStr);
            return Number.isInteger(num) ? 'integer' : 'number';
        }

        // For null/undefined
        if (value === null) return 'null';
        if (value === undefined) return 'undefined';

        // Default to the actual JavaScript type
        return typeof value;
    }

    // Table body
    const tbody = document.createElement('tbody');
    Object.entries(variables).forEach(([key, value], index) => {
        const row = document.createElement('tr');
        row.style.cssText = \`
            \${index % 2 === 0 ? 'background: #f8f9fa;' : 'background: white;'}
            transition: background-color 0.2s;
        \`;
        row.addEventListener('mouseenter', () => row.style.backgroundColor = '#e3f2fd');
        row.addEventListener('mouseleave', () => row.style.backgroundColor = index % 2 === 0 ? '#f8f9fa' : 'white');

        const variableType = getVariableType(key, value);
        const displayValue = String(value);

        row.innerHTML = \`
            <td style="padding: 10px 12px; border-bottom: 1px solid #dee2e6; font-family: monospace; color: #495057;">\${key}</td>
            <td style="padding: 10px 12px; border-bottom: 1px solid #dee2e6; color: #0066cc; font-weight: 500;">\${displayValue}</td>
            <td style="padding: 10px 12px; border-bottom: 1px solid #dee2e6; color: #6c757d; font-size: 12px;">\${variableType}</td>
        \`;
        tbody.appendChild(row);
    });
    table.appendChild(tbody);
    section.appendChild(table);

    return section;
}

