            <div style="margin-top: 30px; padding: 20px; background: #f8f9fa; border-radius: 6px; border-left: 4px solid #007bff;">
                <p style="margin: 0; color: #495057;"><strong>Page ID:</strong> \${pageId}</p>
                <p style="margin: 10px 0 0 0; color: #495057;"><strong>Status:</strong> Ready for content</p>
            </div>
        </div>
    \`;

    // Add to content area
    const contentArea = container.querySelector('.content-area');
    if (contentArea) {
        contentArea.appendChild(pageContent);
    }

    return pageContent;
}

// Assemble the navigation
navContent.appendChild(siteTitle);
navContent.appendChild(navMenu);
navContainer.appendChild(navContent);

// Create content area
const contentArea = document.createElement('div');
contentArea.className = 'content-area';
contentArea.style.cssText = \`
    padding: 20px;
    background: #f8f9fa;
    min-height: 500px;
\`;

// Assemble the complete component
container.appendChild(navContainer);
container.appendChild(contentArea);

// Add the complete navigation component to the document
document.body.appendChild(container);

// Initialize with first page
if (pages.length > 0) {
    showPage(pages[0].id);
}

console.log('Page navigation menu initialized with pages:', pages.map(p => p.name));

// Function to refresh pages from builder
function refreshNavPages() {
    const newPages = getBuilderPages();

    // Clear existing nav buttons
    navMenu.innerHTML = '';

    // Recreate navigation buttons
    newPages.forEach((page, index) => {
        const navButton = document.createElement('a');
        navButton.href = page.url;
        navButton.textContent = page.name;
        navButton.setAttribute('data-page-id', page.id);
        navButton.style.cssText = \`
            color: white;
            text-decoration: none;
            padding: 18px 20px;
            display: block;
            transition: all 0.3s ease;
            font-weight: 500;
            letter-spacing: 0.3px;
            cursor: pointer;
        \`;

        if (index === 0) {
            navButton.style.background = 'rgba(255,255,255,0.2)';
            navButton.style.fontWeight = '600';
            navButton.classList.add('active');
        }

        navButton.onmouseenter = () => {
            if (!navButton.classList.contains('active')) {
                navButton.style.background = 'rgba(255,255,255,0.15)';
                navButton.style.transform = 'translateY(-2px)';
            }
        };

        navButton.onmouseleave = () => {
            if (!navButton.classList.contains('active')) {
                navButton.style.background = 'transparent';
                navButton.style.transform = 'translateY(0)';
            }
        };

        navButton.onclick = (e) => {
            e.preventDefault();
            const allButtons = navMenu.querySelectorAll('a');
            allButtons.forEach(btn => {
                btn.classList.remove('active');
                btn.style.background = 'transparent';
                btn.style.fontWeight = '500';
            });
            navButton.classList.add('active');
            navButton.style.background = 'rgba(255,255,255,0.2)';
            navButton.style.fontWeight = '600';
            navButton.style.transform = 'translateY(0)';
            showPage(page.id);
            console.log(\`Navigated to page: \${page.name}\`);
        };

        navMenu.appendChild(navButton);
    });

    // Update pages array
    pages.length = 0;
    pages.push(...newPages);

    console.log('Navigation refreshed with updated pages:', pages.map(p => p.name));
}

// Make refresh function available globally if needed
window.refreshNavPages = refreshNavPages;`
  }
