    console.log('apiVars keys:', Object.keys(apiVars));
    console.log('typeof globalVariables:', typeof globalVariables);
    console.log('typeof apiVariables:', typeof apiVariables);
    try {
        if (typeof globalVariables !== 'undefined') {
            console.log('globalVariables direct:', globalVariables);
        }
        if (typeof apiVariables !== 'undefined') {
            console.log('apiVariables direct:', apiVariables);
        }
    } catch (e) {
        console.log('Direct access error:', e.message);
    }
    console.log('=== End Variables Template Debug ===');
    
    // Create content container for variable sections (insert before refresh controls)
    let refreshControls = container.querySelector('.refresh-controls');
    const insertBeforeElement = refreshControls || null;
    
    // Add Global Variables section
    if (globalVars && Object.keys(globalVars).length > 0) {
        const globalSection = createVariableTable(globalVars, 'Global Variables', '#d4edda');
        globalSection.classList.add('variable-section');
        container.insertBefore(globalSection, insertBeforeElement);
    } else {
